for(int i=0; i < 4; ++i){
for(int k=0; k < 5; ++k){
draw((0,i)--(4,i));
draw((k,0)--(k,3));
} }

draw((0,0)--(1,3));
draw((3,3)--(4,0));

label("$A$",(0,0),SW);
label("$B$",(4,0),SE);
label("$C$",(4,3),NE);
label("$D$",(0,3),NW);
