label("$a^2 - b^2$", (B + C)/2, S);
label("$2ab$", (A + C)/2, E);
label("$a^2 + b^2$", (A + B)/2, NW);
[/asy]

Hence,
\[\sin x = \boxed{\frac{2ab}{a^2 + b^2}}.\]

